TRP_Weathers.setup = function(){
	var keys = Object.keys(EFFECTS);
	var userTypeId = 101;
	for(const key of keys){
		if(DISABLED_TYPES[key])continue;
		DISABLED_TYPES[key] = userTypeId++;
	}
};



TRP_Weathers.regionData = {};
TRP_Weathers._lastMapId = 0
TRP_Weathers.onMapStart = function(transfer){
	if(this._lastMapId===$gameMap._mapId){
		this._lastMapId = $gameMap._mapId;
		this.regionData = {};
	}

	if($trpWeathers){
		if(transfer){
			$trpWeathers.onTransfer();
		}else{
			$trpWeathers.onSceneMapStart();
		}
	}
};

TRP_Weathers.prototype.initialize = function(){
	this._data = {};
	this._keys = [];
}
TRP_Weathers.prototype.willSave = function(){
	for(const key of this._keys){
		this._data[key].willSave();	
	}
};
TRP_Weathers.prototype.tryMigrateElems = function(){
	if ($gameSystem.versionId() === $dataSystem.versionId)return;

	for(var i=this._keys.length-1; i>=0; i=(i-1)|0){
		var key = this._keys[i];
		var weather = this._data[key];
		if(!weather.data()){
			//data removed
			this._keys.splice(i,1);
			delete this._data[key];
			continue;
		}
		weather.tryMigrateElems();
	}
};

/* onSceneMapStart
===================================*/
TRP_Weathers.prototype.onSceneMapStart = function(){
	for(const key of this._keys){
		this._data[key].onSceneMapStart();
	}
};

/* onTransfer
===================================*/
TRP_Weathers._onTransfer = false;
TRP_Weathers._instantInterpreter = null;
TRP_Weathers._hasPgCommandMVinScript = false;

/* InstantInterpreter
===================================*/
function InstantInterpreter(){
	this.initialize.apply(this, arguments);
}
TRP_Weathers.InstantInterpreter = InstantInterpreter;
InstantInterpreter.prototype = Object.create(Game_Interpreter.prototype);
InstantInterpreter.prototype.constructor = InstantInterpreter;
InstantInterpreter.prototype.initialize = function(){
	Game_Interpreter.prototype.initialize.call(this,0);
};
InstantInterpreter.prototype.clear = function(){
	Game_Interpreter.prototype.clear.call(this);
	this.noEdit = false;
};
InstantInterpreter.prototype.update = function(){
	while(this.isRunning()){
		if(this.updateChild())break;
		this.executeCommand();
		if(this.checkFreeze())break;
	}
};
InstantInterpreter.prototype.setupChild = function(list, eventId){
	this._childInterpreter = new InstantInterpreter(this._depth + 1);
	this._childInterpreter.setup(list,eventId,this._noEdit);
};
InstantInterpreter.prototype.command357 = function(params){
	var pluginName = Utils.extractFileName(params[0]);
	if(pluginName==='TRP_Weather'){
		if(this.noEdit && params[3].editFlag){
			params[3].editFlag = false;
		}
	}
	PluginManager.callCommand(this,pluginName,params[1],params[3]);
	return true;
};
InstantInterpreter.prototype.pluginCommand = function(command, args){
	if(this.noEdit && commandNames.includes(command)){
		if(args[0]==='edit'){
			args[0] = 'set';
		}else if(TRP_CORE.last(args==='edit')){
			args.pop();
		}
	}
	Game_Interpreter.prototype.pluginCommand.call(this,command,args);
};

TRP_Weathers.prototype.onTransfer = function(){
	TRP_Weathers._onTransfer = true;
	//check retain flags
	var lastKeys = [];
	for(const key of this._keys){
		var weather = this._data[key];
		weather.__cache = null;
		weather.cache.onRetain = true;
		lastKeys.push(key);
	}


	//prepare interpreter
	var interpreter = TRP_Weathers._weatherInterpreter;
	if(!interpreter){
		interpreter = TRP_Weathers._weatherInterpreter = new InstantInterpreter();
		TRP_Weathers._hasPgCommandMVinScript = PluginManager._scripts.includes('PluginCommandMVInScriptArea');
	}


	//execute WEATHER event
	for(const event of $gameMap._events){
		if(!event)continue
		var eventData = event.event();
		if(!(eventData?.name==='WEATHER'))continue;
		if(!event.page())continue;

		interpreter.setup(event.list(),event._eventId);
		interpreter.noEdit = eventData.meta.noEdit;
		interpreter.update();

		$gameMap.eraseEvent(event._eventId);
	}

	//clear old weathers
	for(const key of lastKeys){
		var weather = this._data[key];
		if(!weather || !weather.cache.onRetain)continue;

		if(!weather._retain){
			weather.clear(0);
		}else{
			weather.onRetain();
			if(weather._region){
				weather.setupRegion()
			}
		}
	}

	TRP_Weathers._onTransfer = false;

	if($gameMap._trpFogTextures){
		SceneManager._scene?._spriteset?.updateTrpFogTextures();
	}
};


/* pluginCommand
===================================*/
TRP_Weathers.prototype.pluginCommand = function(interpreter,args){
	var sub = args.shift().toLowerCase();
	TRP_Weathers.convertEscapeCharacters(args);
	this._pluginCommand(interpreter,sub,args);
};

TRP_Weathers.convertEscapeCharacters = function(args){
	var length = args.length;
	for(var i=0; i<length; i=(i+1)|0){
		if(typeof args[i] !== 'string')continue;
		var arg = args[i];
		arg = arg.replace(/\\/g, "\x1b");
		arg = arg.replace(/\x1bV\[(\d+)\]/gi, (_, p1) =>
			$gameVariables.value(parseInt(p1))
		);
		arg = arg.replace(/\x1bV\[(\d+)\]/gi, (_, p1) =>
			$gameVariables.value(parseInt(p1))
		);
		arg = arg.replace(/\x1bJ\[(.+?)]/gi,function(_, p1){
			return eval(p1)||'';
		})
		args[i] = arg;
	}
};
TRP_Weathers.prototype._pluginCommand = function(interpreter,sub,args){
	switch(sub){
	case 'set':
		if(TRP_CORE.remove(args,'edit')){
			this.commandEdit(...args);
		}else{
			this.commandSet(...args);
		}
		break;
	case 'clear':
		this.commandClear(...args);
		break;
	case 'edit':
		this.commandEdit(...args);
		break;
	case 'disable':
		this.commandDisable(...args);
		break;
	case 'enable':
		this.commandEnable(...args);
		break;
	case 'retain':
		this.retain(args[0],supplementDefBool(true,args[1]));
		break;
	case 'flash':
		this.commandFlash(...args);
		break;
	case 'wiggle':
		this.commandWiggle(...args);
		break;
	case 'restoreregion':
		this.commandRestoreRegion(...args);
		break;
	}
};


/* update
===================================*/
TRP_Weathers.prototype.update = function(){
	if(!this._keys.length)return;

	var pos = -1;
	for(var i=this._keys.length-1; i>=0; i=(i-1)|0){
		var key = this._keys[i];
		var data = this._data[key];
		if(!data || data._clear){
			data.destroy();
			this._keys.splice(i,1);
			delete this._data[key];
		}else{
			if(pos<0)pos = this.playerPos();
			data.update(pos);
		}
	}
};
TRP_Weathers.prototype.playerPos = function(){
	return Math.round($gamePlayer._realX)+$dataMap.width*Math.round($gamePlayer._realY);
};


/* setup
===================================*/
TRP_Weathers.prototype.commandSet = function(id,...args){
	if(!id)return devError('TRP_Weather.js-> commandSet: idが設定されていません。');

	var region;
	var easing;
	for(var i=args.length-1; i>=0; i=(i-1)|0){
		switch(args[i]){
		case 'region':
		case 'relative':
			region = 'relative';
			break;
		case 'absolute':
			region = 'absolute';
			break;
		default:
			if(TRP_CORE.easing[args[i]]){
				easing = args[i];
			}
			continue;
		}
		//splice if region or easing found
		args.splice(i,1);
	}

	var weather = this._data[id];
	if(weather?.cache.onRetain){
		weather.onRetain();
	}

	var idx = 0;
	this.set(id,args[idx++],args[idx++],easing||args[idx++],region||args[idx++]);
};

TRP_Weathers._lastSetId = null;
TRP_Weathers.prototype.set = function(id,value,duration,easing=null,region=null,senderId=null){
	if(!$dataTrpWeathers[id]){
		return devError('TRP_Weather.js-> commandSet: ID「'+id+'」の設定が存在しません。');
	}
	TRP_Weathers._lastSetId = id;

	var ignoreMiddle;
	if(!isNaN(value)){
		value = Number(value);
		if(value<0){
			value = -value;
			ignoreMiddle = true;
		}
	}

	var weather = this._data[id];
	if(weather){
		weather.set(value,duration,easing,region,ignoreMiddle);
		return;
	}

	if(value===0||value==='0')return;

	var callChain = null;
	if(senderId){
		var sender = this._data[senderId];
		if(sender){
			callChain = sender._callChain?.concat();
		}
		callChain = callChain||[];
		callChain.push(senderId);
	}

	weather = new TRP_Weather(id,value,duration,easing,region,ignoreMiddle,callChain);
	this._keys.push(id);
	this._data[id] = weather;
};

/* edit
===================================*/
TRP_Weathers.prototype.commandEdit = function(id,value,duration,region){
	this.commandSet(...arguments);
};

/* clear
===================================*/
TRP_Weathers.prototype.commandClear = function(id,duration,easing=null){
	if(!id){
		for(var i=this._keys.length-1; i>=0; i=(i-1)|0){
			this.clear(this._keys[i],duration,easing);
		}
	}else{
		this.clear(id,duration,easing);
	}
};
TRP_Weathers.prototype.clear = function(id,duration,easing){
	var weather = this._data[id];
	if(weather){
		weather.clear(duration,easing);
	}
};

/* disable
===================================*/
TRP_Weathers.prototype.commandDisable = function(id,type,enableFlag){
	id = id||TRP_Weathers._lastSetId;

	var weather = this._data[id];
	if(!weather)return;

	if(enableFlag==='true')enableFlag = 1;
	else enableFlag = supplementDefNum(0,enableFlag);

	if(enableFlag>0){
		var allFlag = enableFlag>1;
		weather.setEnabled(type,allFlag);
	}else{
		weather.setDisabled(type);
	}
};
TRP_Weathers.prototype.commandEnable = function(id,type,allFlag){
	id = id||TRP_Weathers._lastSetId;
	var weather = this._data[id];
	if(!weather)return;

	allFlag = supplementDefBool(false,allFlag);
	weather.setEnabled(type,allFlag);
};

/* retain
===================================*/
TRP_Weathers.prototype.retain = function(id,value=true){
	id = id||TRP_Weathers._lastSetId;
	if(this._data[id]){
		this._data[id].retain(value);
	}
};


/* flash
===================================*/
TRP_Weathers.prototype.commandFlash = function(id,value,duration,easing=null,inDuration=0,inEasing=null){
	if(value)value = Number(value);
	if(duration)duration = Number(duration);
	if(inDuration)inDuration = Number(inDuration);
	this.flash(id,value,duration,easing,inDuration,inEasing);
};
TRP_Weathers.prototype.flash = function(id,value=10,duration=60,easing=null,inEasing=null){
	this.set(id,value,0,inEasing);
	this.clear(id,duration,easing);
};

/* wiggle
===================================*/
TRP_Weathers.prototype.commandWiggle = function(id,aStrength,aInterval,...exArgs){
	id = id||TRP_Weathers._lastSetId;
	if(!this._data[id])return;
	var strength = supplementDefNum(0.5,aStrength);
	var interval = supplementDefNum(10,aInterval);
	exArgs = exArgs.map(a=>Number(a));
	this._data[id].startWiggler(strength,interval,...exArgs);
};

/* regionIds
===================================*/
TRP_Weathers._restoredLog = [];
TRP_Weathers.restore = function(){
	$trpWeathers.commandRestoreRegion()
};
TRP_Weathers.prototype.commandRestoreRegion = function(id){
	if(!$gameTemp.isPlaytest() || !Utils.isNwjs())return;

	var success = false;
	if(!id){
		for(const id of this._keys){
			var data = this._data[id];
			if(data?._region){
				success = this.tryRestoreRegion(id,true)||success;
			}
		}
	}else{
		success = this.tryRestoreRegion(id)||false;
	}

	if(success){
		SoundManager.playSave();
		alert('マップデータを保存しました！');
	}
};

TRP_Weathers.prototype.tryRestoreRegion = function(id,noAlert=false){
	var logKey = id+':'+$gameMap._mapId;
	if(TRP_Weathers._restoredLog.includes(logKey))return false;
	TRP_Weathers._restoredLog.push(logKey);

	var metaKey = "weather-"+id;
	var metaData = $dataMap.meta[metaKey]
	if(!metaData){
		if(!noAlert){
			SoundManager.playBuzzer();
			alert('メモ欄に対象の天候IDのリージョン設定がありません。（<%1:データ>）'.format(metaKey));
		}
		return;
	}
	metaData = JSON.parse(metaData);

	var name = "天候:"+id;
	var engName = "weather:"+id;
	var mapId = $dataMapInfos.find(info=>{
		if(!info||info.parentId!==$gameMap._mapId)return false;
		var infoName = info.name.replace('：',':');
		return infoName===name||infoName===engName;
	})?.id||0;
	if(mapId){
		SoundManager.playBuzzer();
		alert('既に直下にリージョン設定用のマップ「%1」が存在します。'.format($dataMapInfos[mapId].name));

		return;
	}

	var _Dev = TRP_CORE.DevFuncs;
	var dataFiles = _Dev.readdirSync('data');
	var dstId = 0;
	for(var i=1; i<1000; i=(i+1)|0){
		if($dataMapInfos[i])continue;
		if(dataFiles.includes(TRP_CORE.mapFileName(i)))continue;
		dstId = i;
		break;
	}
	if(!dstId){
		SoundManager.playBuzzer();
		alert('マップIDの空きがありません。(未削除のdataフォルダ下のマップデータも含む）');
		return;
	}

	var filePath = TRP_CORE.mapFilePath($gameMap._mapId);
	var mapData = JSON.parse(_Dev.readFile(filePath));

	//setup region
	var size = mapData.width*mapData.height;
	var i0 = 5*size;
	for(var i=0; i<size; i=(i+1)|0){
		mapData.data[i0+i] = metaData[i];
	}
	mapData.events = [];

	//saveFile
	var dstPath = TRP_CORE.mapFilePath(dstId);
	_Dev.saveFile(mapData,dstPath)

	//mapInfos
	var mapInfosPath = 'data/MapInfos.json';
	var mapInfos = JSON.parse(_Dev.readFile(mapInfosPath));
	// var backupPath = TRP_CORE.BACK_UP_DIR+'MapInfos.json'
	// _Dev.saveFile(mapInfos,backupPath);

	var parentInfo = $dataMapInfos[$gameMap._mapId];
	mapInfos[dstId] = {
		"id":dstId,
		"expanded":true,
		"name":name,
		// "order":mapInfos.length,
		"order":1000,
		"parentId":$gameMap._mapId,
		"scrollX":parentInfo.scrollX,
		"scrollY":parentInfo.scrollY
	};
	_Dev.saveFile(mapInfos,mapInfosPath);

	return true;
};


TRP_Weather._analyzingRegionIdMapNum = 0;
TRP_Weather._analyzingRegionIdCopyText = '';
TRP_Weathers.analyzeRegionIds = function(id){
	if(this.regionData[id])return;

	var metaKey = "weather-"+id;
	if($dataMap.meta[metaKey]){
		this.regionData[id] = JSON.parse($dataMap.meta[metaKey]);
		return;
	}

	var name = "天候:"+id;
	var engName = "weather:"+id;
	var mapId = $dataMapInfos.find(info=>{
		if(!info||info.parentId!==$gameMap._mapId)return false;
		var infoName = info.name.replace('：',':');
		return infoName===name||infoName===engName;
	})?.id||0;
	if(!mapId){
		if($gameTemp.isPlaytest()){
			throw new Error('天候リージョン設定用の子マップ名「%1」がありません。'.format(name))
		}else{
			return;
		}
	}

	var errName = 'TRP_Weather:regionMapData'
	var src = this.mapFileName(mapId);
	var xhr = new XMLHttpRequest();
	var url = "data/" + src;
	xhr.open("GET", url);
	xhr.overrideMimeType("application/json");

	TRP_Weather._analyzingRegionIdMapNum += 1;
	xhr.onload = () => {
		if(xhr.status < 400){
			var result = this._analyzeRegionIds(JSON.parse(xhr.responseText));
			this.regionData[id] = result;
			if($gameTemp.isPlaytest() && analyeRegionOption!=='none'){
				var text = '<weather-%1:%2>'.format(id,JSON.stringify(result));
				TRP_Weather._analyzingRegionIdCopyText += text+'\n';
				TRP_Weather._analyzingRegionIdMapNum -= 1;
				if(TRP_Weather._analyzingRegionIdMapNum<=0){
					var copyText = TRP_Weather._analyzingRegionIdCopyText;
					TRP_Weather._analyzingRegionIdMapNum = 0;
					TRP_Weather._analyzingRegionIdCopyText = '';
					if(analyeRegionOption==='save'){
						if(!confirm('マップのメモ欄にリージョン解析データを上書き保存しますか？\n(※編集中プロジェクトデータの上書きに注意！)')){
							SoundManager.playCancel();
							return;
						}
						var mapId = $gameMap._mapId;
						var mapFilePath = TRP_CORE.mapFilePath(mapId);
						var mapData = JSON.parse(TRP_CORE.DevFuncs.readFile(mapFilePath));
						if(mapData.note[mapData.note.length-1]!=='\n'){
							mapData.note += '\n';
						}
						mapData.note += copyText;
						TRP_CORE.DevFuncs.saveMapFile(mapData,mapId);
						SoundManager.playSave();
						if(!isMZ){
							alert('マップデータを保存しました。\nプロジェクトを開き直すと反映されます。')
						}
					}else if(analyeRegionOption==='copy'){
						var listener = function(e){
							e.clipboardData.setData('text/plain' , copyText);
							e.preventDefault();
							document.removeEventListener('copy', listener);
							confirm('天候設定用リージョンデータをクリップボードにコピーしました。\nマップのメモ欄に貼り付けると読み込みが高速化します。');
						}
						document.addEventListener('copy' , listener);
						document.execCommand('copy');
					}
				}
			}
		}else{
			DataManager.onXhrError(errName, src, url);
		}
	};
	xhr.onerror = () => DataManager.onXhrError(errName,src,url);
	xhr.send();
};


TRP_Weathers._analyzeRegionIds = function(data){
	var w = data.width;
	var h = data.height;
	var result = [];
	var size = w*h;
	var i0 = 5*size;
	for(var i=i0; i<i0+size; i=(i+1)|0){
		var r = data.data[i]||0;
		if(r<=100){
			result.push(r);
		}else{
			result.push(0);
		}
	}
	return result;
};

//helper
TRP_Weathers.mapFileName = function(mapId){
	return  "Map%1.json".format(mapId.padZero(3));
};
TRP_Weathers.prototype.isCircularCall = function(currentId,targetId){
	if(currentId===targetId)return true;
	var weather = this._data[currentId];
	if(!weather)return false;
	return weather._callChain?.contains(targetId);
};

TRP_Weathers.relatedWeatherIds = function(targetId){
	var ids = [targetId];
	var nexts = [targetId];
	while(nexts.length){
		var currents= nexts;
		nexts = [];
		for(const id of currents){
			var data = $dataTrpWeathers[id];
			if(!data)continue;
			for(const elem of data.elems){
				if(elem.type!=='weather')continue;
				var configName = elem.typeParams.configName;
				if(!ids.includes(configName)){
					ids.push(configName);
					nexts.push(configName);
				}
			}
		}
	}
	return ids;
};



