// TRP_Weather
//=============================================================================
TRP_Weather.prototype.initialize = function(id,value,duration,easing,region,ignoreMiddle,callChain){
	this._id = id;

	this._clear = false;
	this._clearDuration = 0;
	this._region = null;
	this._disabled = null;
	this._retain = false;

	this._value = -1;
	this._changeCount = 0;

	this._elems = [];
	this._callChain = callChain;

	this.wiggler = null;
	this.__cache = null;

	this.setupElems();

	this.set(value,duration,easing,region,ignoreMiddle,true);
};

TRP_Weather.prototype.set = function(value,duration,easing,region,ignoreMiddle,init=false){
	var data = this.data();

	var valueNotDef = value!==undefined&&value!=='d'&&value!=='def';
	if(init && region==='relative'){
		value = supplementDefNum(10,value);
	}else{
		value = supplementDefNum(data.value,value);
	}
	duration = this.durationWithDefault(duration,value);
	

	this._clear = false;
	this._clearDuration = 0;
	if(region==='absolute'||region==='relative'){
		this.setupRegion(region,value,duration,easing);
		return;
	}else if(region==='none'){
		this._region = null;
	}
	
	if(!init){
		if(valueNotDef || (this._clear||this._clearDuration)){
			//change src value
			this.setSrcValue(value,duration,easing,ignoreMiddle);
		}
	}else{
		//init
		this.setValue(value,duration,easing,ignoreMiddle);
	}
}

TRP_Weather.prototype.setupRegion = function(region=this.regionType(),value=this._region?.[1],duration,easing){
	this._region = [region==='absolute'?0:1,value];

	TRP_Weathers.analyzeRegionIds(this._id);
	
	// if(TRP_Weathers._onTransfer){
	// 	//transfer -> set value with no duration
	// 	this.updateRegion($trpWeathers.playerPos(),0);
	// }
	this.updateRegion($trpWeathers.playerPos(),TRP_Weathers._onTransfer ? 0 : duration,easing);
};


TRP_Weather.prototype.willSave = function(){
	this.__cache = null;
	for(const elem of this._elems){
		elem.cache = null;
	}
};
Object.defineProperty(TRP_Weather.prototype, 'cache', {
	get: function() {
		if(!this.__cache){
			this.__cache = {
				onRetain:false,
				lastPos:-1,
				regionData:null,
			}
		}
		return this.__cache;
	},
	configurable: true
});

TRP_Weather.prototype.tryMigrateElems = function(){
	var data = this.data();
	if(data.elems.length>this._elems.length){
		var addedNum = data.elems.length-this._elems.length;
		for(var i=0; i<addedNum; i=(i+1)|0){
			this.addElem();
			var idx = this._elems.length-1;
			var elem = this._elems[idx];
			var v = this._valueChanger ? this._valueChanger[0] : this._value;
			var d = this._valueChanger ? (this._valueChanger[3]-this._valueChanger[2]) : 0;
			this.setElemValue(idx,elem,data.elems[idx],v,d);
		}
	}else if(data.elems.length<this._elems.length){
		this._elems.length = data.elems.length;
	}
};


/* onSceneMapStart
===================================*/
TRP_Weather.prototype.onSceneMapStart = function(){
	var data = this.data();
	var length = data.elems.length;

	var regionValue = this.cache.regionData ? this.__cache.regionData[this.__cache.lastPos] : -1;
	for(var i=0; i<length; i=(i+1)|0){
		var elemData = data.elems[i];
		var effect = EFFECTS[elemData.type];
		if(!effect.onAfterSceneStart)continue;

		if(typeof effect.onAfterSceneStart==='function'){
			if(!effect.onAfterSceneStart(elemData))continue;
		}

		var elem = this._elems[i];
		var v = regionValue>-1 ? regionValue : elem.value;
		this.setElemValue(i,elem,elemData,v,0,null,false,false,true);
	}
};


TRP_Weather.prototype.analyzeRegionValueOnMapStart = function(){
	var regionValue = -1;
	if(this._region){
		if(!this.__cache.regionData){
			TRP_Weathers.analyzeRegionIds(this._id);
		}
		var regionData = this.__cache.regionData = TRP_Weathers.regionData[this._id];
		if(!regionData)return;

		var pos = $trpWeathers.playerPos();
		regionValue = regionData[pos];
		this.__cache.pos = pos;
		if(this.regionType()==='relative'){
			regionValue *= this._region[1]/10;
		}
	}
	return regionValue;
};


/* retain
===================================*/
TRP_Weather.prototype.retain = function(value){
	this._retain = value;

	var data = this.data();
	for(const elemData of data.elems){
		if(elemData.type!=='weather')continue;
		var child = $trpWeathers._data[elemData.typeParams.configName]
		child?.retain(value);
	}
}
TRP_Weather.prototype.onRetain = function(){
	this.cache.onRetain = false;

	var data = this.data();
	var length = data.elems.length;

	var regionValue = this.analyzeRegionValueOnMapStart();
	for(var i=0; i<length; i=(i+1)|0){
		var elemData = data.elems[i];
		var effect = EFFECTS[elemData.type];
		if(!effect.onAfterTransfer)continue;
		if(typeof effect.onAfterTransfer==='function'){
			if(!effect.onAfterTransfer(elemData))continue;
		}

		var elem = this._elems[i];
		var v = regionValue>-1 ? regionValue : elem.value;
		this.setElemValue(i,elem,elemData,v,0,null,false,false,true);

		if(elemData.type==='weather'){
			var child = $trpWeathers._data[elemData.typeParams.configName]
			child?.onRetain();
		}
	}
};



/* setup
===================================*/
TRP_Weather.prototype.setupElems = function(){
	var data = this.data();
	for(const elemData of data.elems){
		this.addElem(elemData);
	}
};
TRP_Weather.prototype.addElem = function(elemData){
	var elem = {
		value:-1,
		clear:-1,
		changer:null,
		next:null,
		easing:null,
		cache:null,
	};
	this._elems.push(elem);
};


/* clear
===================================*/
TRP_Weather.prototype.clear = function(duration=this.duration(0),easing=null){
	if(typeof duration==='string'){
		duration = supplementDefNum(this.duration(0),duration);
	}
	
	this.setValue(0,duration,easing);
	if(duration<=0){
		this._clear = true;
	}else{
		this._clearDuration = duration;
	}
};

/* disable
===================================*/
var DISABLED_TYPES = TRP_Weather.DISABLED_TYPES = {
	none:0,
	normal:1,all:2,region:3,elem:4,
	particle:4,fog:5,filter:6,tint:7,weather:8,defWeather:9,bgs:10,
	//user add 101~ @ TRP_Weathers.setup
};

TRP_Weather.prototype.setDisabled = function(type){
	this._disabled = this._disabled||[];

	var elemIdx = 0;
	if(!isNaN(type)){
		elemIdx = Number(type)-1;
		if(elemIdx<0)return;
		type = 'elem';
	}
	var id = this.disableTypeId(type,elemIdx);
	if(!this._disabled.includes(id)){
		this._disabled.push(id);
	}
};
TRP_Weather.prototype.setEnabled = function(type,enableFlag){
	if(!this._disabled)return;
	var elemIdx = 0;
	if(!isNaN(type)){
		elemIdx = Number(type)-1;
		if(elemIdx<0)return;
		type = 'elem';
	}
	var id = this.disableTypeId(type,elemIdx);
	var idx = this._disabled.indexOf(id);
	if(idx<0)return;
	this._disabled.splice(idx,1);
};
TRP_Weather.prototype.isDisabled = function(type,elemIdx=0){
	if(!this._disabled)return false;
	return this._disabled.includes(this.disableTypeId(type,elemIdx));
};
TRP_Weather.prototype.disableTypeId = function(type,elemIdx){
	if(type==='elem')return DISABLED_TYPES.elem+elemIdx;
	return DISABLED_TYPES[type]
};



/* update
===================================*/
TRP_Weather.prototype.update = function(pos){
	if(this._region && !this._clear && !this._clearDuration &&
		this.cache.lastPos!==pos && !this.isDisabled('region')
	){
		this.updateRegion(pos);
	}

	if(this.wiggler && !this._valueChanger && !this._changeCount && this.wiggler[WIGGLER_INDEXES.baseValue]>0){
		this.updateWiggler();
	}

	if(this._changeCount>0){
		this.updateChanger();
	}

	this.updateElemValues();
	if(this._clearDuration>0){
		this.updateClear();
	}
};
TRP_Weather.prototype.updateChanger = function(){
	this._changeCount -= 1;
	if(this._changeCount<=0){
		this._changeCount = 0;
	}

	var data = this.data();
	for(var i=this._elems.length-1; i>=0; i=(i-1)|0){
		var elem = this._elems[i];
		var elemData = data.elems[i];
		this.updateElemChanger(i,elem,elemData);
	}
};

TRP_Weather.prototype.updateElemValues = function(){
	var elems = this._elems;
	var length = elems.length;
	for(var i=0; i<length; i=(i+1)|0){
		var elem = elems[i];
		if(elem.clear>0){
			elem.clear -= 1;
			if(elem.clear<=0){
				this.clearElem(elem);
			}
		}
	}
};
TRP_Weather.prototype.clearElem = function(elem,idx=this._elems.indexOf(elem)){
	if(!elem){
		elem = this._elems[idx];
		if(!elem)return;
	}
	elem.clear = 0;
	elem.value = -1;
	var elemData = this.data().elems[idx];
	var effect = TRP_Weathers.EFFECTS[elemData.type];
	effect.off(this._id,idx,elem,elemData);
};
TRP_Weather.prototype.updateClear = function(){
	this._clearDuration -= 1;
	if(this._clearDuration>0)return;

	this._clearDuration = 0;
	this._clear = true;
};
TRP_Weather.prototype.destroy = function(){
	var elems = this._elems;
	var length = elems.length;
	for(var i=0; i<length; i=(i+1)|0){
		var elem = elems[i];
		if(elem.clear>0){
			this.clearElem(elem); 
		}
	};
};

/* region
===================================*/
TRP_Weather.prototype.updateRegion = function(pos,duration,easing){
	var data = this.cache.regionData;
	if(!data){
		data = this.__cache.regionData = TRP_Weathers.regionData[this._id];
		if(!data)return;
	}
	this.__cache.lastPos = pos;

	var value = data[pos];
	if(this._region[0]){
		//relative
		value *= this._region[1]/10;
	}

	if(this._value===value||(this._valueChanger&&this._valueChanger[0]===value))return;
	this.setValue(value,duration,easing);
};


/* value
===================================*/
TRP_Weather.prototype.setSrcValue = function(value,duration,easing,ignoreMiddle){
	if(this._region){
		this._region[1] = value;
		if(this._region[0]===0){
			//relative
			if(this.cache.regionData && this.cache.lastPos>=0){
				value *= this.cache.regionData[this.cache.lastPos]/10;
			}
		}
	}
	if(this.wiggler){
		this.wiggler[WIGGLER_INDEXES.baseValue] = value;
	}

	duration = supplementDefNum(
		TRP_Weathers._onTransfer?0:this.duration(value),duration
	);
	this.setValue(value,duration,easing,ignoreMiddle,true);
};

TRP_Weather.prototype.setValue = function(value,duration=this.duration(value),easing=null,ignoreMiddle,fromCmdCall=false){
	if(!this._changeCount && this._value===value)return;
	if(this._disabled){
		if(this.isDisabled('all'))return;
		if(!fromCmdCall && this.isDisabled('normal'))return;
	}

	if(value>0){
		this._clearDuration = 0;
		this._clear = false;
	}

	this._changeCount = 0;
	if(this._value<0){
		this._setValue(0,0);
		if(value===0)return;
	}

	duration = Math.ceil(duration);
	this._changeCount = duration;

	this._setValue(value,duration,easing,ignoreMiddle);
};
TRP_Weather.prototype._setValue = function(value,duration=this.duration(value),easing=null,ignoreMiddle,noSwitch=false){
	if(!this._changeCount && this._value===value)return;
	if(ignoreMiddle===undefined){
		ignoreMiddle = this.isIgnoreMiddleValues()
	}

	if(easing==='linear'){
		easing = null;
	}else if(!TRP_CORE.easing[easing]){
		easing = null;
	}

	var data = this.data();
	var elems = this._elems;
	var length = elems.length;
	for(var i=0; i<length; i=(i+1)|0){
		var elem = elems[i];
		var elemData = data.elems[i];
		this.setElemValue(i,elem,elemData,value,duration,easing,ignoreMiddle,noSwitch);
	}
	this._value = value;
};


const CHNAGER_IDXES = TRP_Weather.CHNAGER_IDXES = {
	count:0,target:1,duration:2,v0:3,
};
TRP_Weather.prototype.setElemValue = function(elemIdx,elem,elemData,value,duration=this.duration(),easing=null,ignoreMiddle=this.isIgnoreMiddleValues(),noSwitch=false,onRetain=false){
	if(!elem || !elemData || elemData.disabled)return true;

	//no change -> return
	if(!onRetain && elem.value===value && !elem.changer)return true;

	//check disabled
	var success = false;
	var effect = TRP_Weathers.EFFECTS[elemData.type];
	if(this._disabled){
		if(this.isDisabled('elem',elemIdx))return true;
		switch(elemData.type){
		case 'particle':
		case 'particleGroup':
			if(this.isDisabled('particle'))return true;
		default:
			if(this.isDisabled(elemData.type))return true;
		}
	}

	//finite value if on change
	var next = elem.next;
	if(next){
		const IDXES = CHNAGER_IDXES;
		elem.value = elem.value+next[IDXES.count]*(next[IDXES.target]-next[IDXES.v0])/next[IDXES.duration];
	}

	// no duration > set
	if(duration<=0){
		this._setElemValue(elemIdx,elem,elemData,value,0,noSwitch,onRetain);
		elem.value = value;
		elem.changer = null;
		elem.next = null;
		elem.easing = null;
		return;
	}

	//changer
	elem.changer = [
		0,value,duration,elem.value,
	];
	elem.next = null;
	elem.easing = easing ? [easing,0] : null;

	this.setElemChangerNextValue(elemIdx,elem,elemData,ignoreMiddle,noSwitch,onRetain);
};

TRP_Weather.prototype.setElemChangerNextValue = function(elemIdx,elem,elemData,ignoreMiddle=false,noSwitch,onRetain){
	var changer = elem.changer;
	if(!changer)return;
	var [totalCount,targetValue,totalDuration,v0] = changer;

	var leftDuration = totalDuration-totalCount;
	var current = Math.max(0,elem.value);

	var target,duration;
	if(ignoreMiddle){
		//direct change
		target = targetValue;
		duration = totalDuration;
	}else{
		//consider middle values
		target = this._getNextElemValueWithTarget(elemData,targetValue,current);

		duration = Math.round(leftDuration*(target-current)/(targetValue-current));
	}

	if(elem.easing){
		var easingPositions = TRP_Weather.PSEUDO_EASING_POSITIONS[elem.easing[0]];
		if(easingPositions){
			var posLen = easingPositions.length;
			do{
				var nextPosIdx = elem.easing[1]++;
				if(nextPosIdx>=posLen-1){
					target = targetValue;
					duration = 0;
					break;
				}else{
					var [t,nextEasePos] = easingPositions[nextPosIdx];
					target = v0+nextEasePos*(targetValue-v0);

					var currentDurPos = totalCount/totalDuration;
					duration = Math.round((t-currentDurPos)*totalDuration);
				}
			}while(duration<=0);
		}
	}

	if(target===targetValue){
		duration = leftDuration;
	}else{
		duration = duration.clamp(0,leftDuration);
	}
	elem.next = [
		0,target,duration,current
	];

	this._setElemValue(elemIdx,elem,elemData,target,duration,noSwitch,onRetain);
	if(duration<=0){
		this.updateElemChanger(elemIdx,elem,elemData,true);
	}
};
TRP_Weather.prototype._getNextElemValueWithTarget = function(elemData,targetValue,currentValue){
	var values = elemData.values;
	var valueLen = values.length;
	if(targetValue-currentValue>0){
		//value up
		for(var vi=0; vi<valueLen; vi=(vi+1)|0){
			var valueData = values[vi];
			if(valueData.value>currentValue){
				return  Math.min(valueData.value,targetValue);
			}
		}
	}else{
		//value down
		for(var vi=valueLen-1; vi>=0; vi=(vi-1)|0){
			var valueData = values[vi];
			if(valueData.value<currentValue){
				return Math.max(valueData.value,targetValue);
			}
		}
	}
	//no middle value -> target
	return targetValue;
}

TRP_Weather.prototype.updateElemChanger = function(elemIdx,elem,elemData,noExceed=false){
	var {changer,next} = elem;
	if(!changer)return;

	var changerCount = changer[CHNAGER_IDXES.count] += (noExceed ? 0 : 1);
	var count = next[CHNAGER_IDXES.count] += (noExceed ? 0 : 1);
	if(count<next[CHNAGER_IDXES.duration])return;

	//finish "next" changer -> update value
	elem.value = next[CHNAGER_IDXES.target];
	elem.next = null;

	if(changer[CHNAGER_IDXES.count]<changer[CHNAGER_IDXES.duration]){
		this.setElemChangerNextValue(elemIdx,elem,elemData);
		return;
	}

	//finish whole changer!
	var finalTarget = changer[CHNAGER_IDXES.target];
	if(elem.value!==finalTarget){
		this._setElemValue(elemIdx,elem,elemData,finalTarget,0);
	}
	elem.changer = null;
};


//only effect, no change value
TRP_Weather.prototype._setElemValue = function(elemIdx,elem,elemData,value,duration,noSwitch=false,onRetain=false){
	var lastOn = onRetain ? false : TRP_Weather.isElemOn(elem.value,elemData);
	var on = noSwitch ? lastOn : TRP_Weather.isElemOn(value,elemData);
	if(!lastOn && !on){
		return true;
	}

	var effect = EFFECTS[elemData.type];
	if(!effect)return true;

	if(lastOn !== on){
		elem.__cache = null;
		if(on){
			effect.on(this._id,elemIdx,elem,elemData);
			elem.clear = 0;
			elem.value = 0;

			//init value for 0
			if(duration>0){
				var params0 = TRP_Weather.paramsForValue(0,elemData);
				if(!effect.setValue(this._id,elemIdx,elem,elemData,0,params0,0)){
					return false;
				}
			}
		}else{
			//off
			if(duration<=0){
				var params = TRP_Weather.paramsForValue(0,elemData);
				effect.setValue(this._id,elemIdx,elem,elemData,0,params,0);
				effect.off(this._id,elemIdx,elem,elemData);
				elem.clear = 0;
				return true;
			}else{
				elem.clear = duration;
			}
		}
	}else{
		elem.clear = 0;
	}

	var params = TRP_Weather.paramsForValue(value,elemData);
	duration = Math.ceil(duration)

	if(!effect.setValue(this._id,elemIdx,elem,elemData,value,params,duration)){
		return false;
	}

	return true;
};



//=============================================================================
// TRP_Weather: Wiggler
//=============================================================================
TRP_Weather.prototype.startWiggler = function(strength=0.5,interval=10,intervalWidth=0.3,wait=0,waitWidth=0.3,back=0,direction=0,options=0){
	if(!strength){
		this.wiggler = null;
		return;
	}
	if(typeof back === 'string'){
		back = WIGGLER_BACK[back]||0;
	}
	if(typeof direction === 'string'){
		direction = WIGGLER_DIRECTION[direction]||0;
	}

	var baseValue = this.wiggler?.[WIGGLER_INDEXES.baseValue] ?? this._value;
	var sign;
	if(direction===WIGGLER_DIRECTION.plus){
		sign = 1;
	}else if(direction===WIGGLER_DIRECTION.minus){
		sign = -1;
	}else{
		sign = Math.random()<0.5?-1:1;
	}

	this.wiggler = [
		//baseValue,sign,strength,interval,intervalWidth,wait,waitWidth,back,direction,options
		baseValue,sign,
		strength,interval,intervalWidth,wait,waitWidth,back,direction,options,		
	];
};

var WIGGLER_OPTIONS = TRP_Weather.WIGGLER_OPTIONS = {
	discrete:1<<0,
	fixedDelta:1<<1,
};
var WIGGLER_INDEXES = TRP_Weather.WIGGLER_INDEXES = {
	baseValue:0,sign:1,
	strength:2,interval:3,intervalWidth:4,wait:5,waitWidth:6,back:7,direction:8,option:9,
};
var WIGGLER_BACK = TRP_Weather.WIGGLER_BACK = {
	none:0,back:1,flashIn:2,flashOut:3
};
var WIGGLER_DIRECTION = TRP_Weather.WIGGLER_DIRECTION = {
	normal:0,random:1,plus:2,minus:3
};

TRP_Weather.prototype.updateWiggler = function(){
	var w = this.wiggler;
	var [baseValue,sign,strength,interval,intervalWidth,wait,waitWidth,back,direction,options] = w;

	//reverse sign
	if(direction===0){
		w[WIGGLER_INDEXES.sign] *= -1;
	}else if(direction===WIGGLER_DIRECTION.random){
		w[WIGGLER_INDEXES.sign] = Math.random()<=0.5 ? -1 : 1;
	}


	// calc duration
	var duration = interval * ((1-intervalWidth)+Math.random()*2*intervalWidth);
	var waitCount = wait*((1-waitWidth)+Math.random()*2*waitWidth);

	//calc base with direction
	var base;
	if(direction===WIGGLER_DIRECTION.plus){
		base = baseValue.clamp(0.01,10-strength);
	}else if(direction===WIGGLER_DIRECTION.minus){
		base = baseValue.clamp(strength,10);
	}else{
		strength /= 2;
		base = baseValue.clamp(strength,10-strength);
	}

	//apply back
	var value;
	if(back){
		if(this._value!==base){
			//back phase
			value = base;
			if(back===WIGGLER_BACK.flashOut){
				duration = 0;
			}else{
				duration *= 0.5;
			}
		}else{
			//go phase
			waitCount = 0;
			if(back===WIGGLER_BACK.flashIn){
				duration = 0;
			}else{
				duration *= 0.5;
			}
		}
	}

	// calc random strength
	if(value===undefined){
		var t;
		if(options&WIGGLER_OPTIONS.fixedDelta){
			t = 1;
		}else{
			t = (Math.random() + Math.random()) / 2; // [0,1]の中央寄り分布
		}
		var delta = sign * strength * t;
		value = base + delta;
	}

	//setValue (apply dicrete)
	duration = Math.round(duration)||1;
	if(options&WIGGLER_OPTIONS.discrete){
		this._setValue(value, 0);
	}else{
		this.setValue(value, duration);
	}


	//nextUpdate -> interval + wait
	this._changeCount = Math.ceil(duration+waitCount);
};


//=============================================================================
// TRP_Weather: accessor&helper
//=============================================================================
TRP_Weather.prototype.baseValue = function(){
	if(this.wiggler)return this.wiggler[WIGGLER_INDEXES.baseValue];
	if(this._valueChanger)return this._valueChanger[0];
	return this._value;
};

TRP_Weather.prototype.data = function(){
	return $dataTrpWeathers[this._id];
};
TRP_Weather.prototype.duration = function(value=Math.max(0,this._value)){
	return Math.abs(value-Math.max(0,this._value))*this.data().speed;

};
TRP_Weather.prototype.isIgnoreMiddleValues = function(){
	return this.data().ignoreMiddle;
};


TRP_Weather.prototype.durationWithDefault = function(duration,value){
	return supplementDefNum(
		TRP_Weathers._onTransfer?0:this.duration(value),duration
	);
};
TRP_Weather.prototype.regionType = function(){
	return this._region?(this._region[0]===1?'relative':'absolute'):null;
};


TRP_Weather.isSceneStarting = function(){
	return SceneManager._scene.isFading() && SceneManager._scene._fadeSign>0;
};


TRP_Weather.isElemOn = function(value,elemData){
	if(value<=0)return false;

	var on = false;
	var hasParams = false;
	for(const valueData of elemData.values){
		if(valueData.value>value)break;
		on = valueData.on;
	}
	return on;
};
TRP_Weather.paramsForValue = function(value,elemData){
	var values = {
		start:null,
		end:null,
	};

	for(const valueData of elemData.values){
		if(value>=valueData.value){
			values.start = valueData;
		}else{
			values.end = valueData;
			break;
		}
	}

	if(!(values.start?.params) && !(values.end?.params)){
		return null;
	}

	var rate = 0;
	if(!values.start){
		rate = 1;
	}else if(values.end){
		rate = (value-values.start.value)/((values.end.value-values.start.value)||1)
	}

	var keys = Object.keys(values.start?.params || values.end.params);
	var params = {keys};
	for(const key of keys){
		TRP_Weather.setParamForValue(key,rate,params,values.start?.params,values.end?.params);
	}
	return params;
};
TRP_Weather.setParamForValue = function(key,rate,params,sParams,eParams){
	var any = (sParams||eParams)[key];
	var type = typeof any;
	if(type==='number'){
		var s = sParams ? sParams[key] : 0;
		var e = eParams ? eParams[key] : 0;
		if(key==='frequency'){
			//use log
			params[key] = Math.exp(
				Math.log(s)+rate*(Math.log(e||0.0001)-Math.log(s||0.0001))
			);
		}else{
			params[key] = s+rate*(e-s);
		}
	}else if(type==='string'){
		if(sParams&&sParams[key]
			&&eParams&&eParams[key]
			&&/[0-9]/.test(any)
		){
			//string params
			var result = "";
			var sStr = sParams[key];
			var eStr = eParams[key];
			var length = sStr.length;
			var sMatch = sStr.match(/[+-]?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?/gi);
			var eMatch = eStr.match(/[+-]?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?/gi);
			if(sMatch.length===eMatch.length){
				while(sStr.length){
					var sNum = sMatch.shift();
					var eNum = eMatch.shift();
					if(sNum&&eNum){
						var sIdx = sStr.indexOf(sNum);
						var eIdx = eStr.indexOf(eNum);
						if(sIdx!==eIdx){
							result = any;
							break;
						}

						var prefix = sStr.substring(0,sIdx);
						if(prefix !== eStr.substring(0,eIdx)){
							result = any;
							break;
						}
						result += prefix;

						sStr = sStr.substring(sIdx+sNum.length);
						eStr = eStr.substring(eIdx+eNum.length);
						var s = Number(sNum);
						var e = Number(eNum);
						result += s+rate*(e-s);
					}else{
						if(sStr!==eStr){
							result = any;
						}else{
							result += sStr;
						}
						break;
					}
				}
				params[key] = result;
			}else{
				params[key] = any;
			}
		}else{
			params[key] = any;
		}
	}else if(Array.isArray(any)){
		//array params
		var length = any.length
		params[key] = [];

		for(var i=0; i<length; i=(i+1)|0){
			this.setParamForValue(
				i,rate,params[key],
				sParams?.[key],eParams?.[key]
			);
		}
	}else if(type==='object'){
		params[key] = {};
		for(const childKey of Object.keys(any)){
			this.setParamForValue(
				childKey,rate,params[key],
				sParams?.[key], eParams?.[key]
			);
		}
	}else{
		params[key] = any;
	}
};


TRP_Weathers.elemId = function(weatherId,elemIdx){
	return '_TRPW:'+weatherId+':'+elemIdx;
};




//=============================================================================
// EFFECf -> particle 
//=============================================================================
var EFFECTS = TRP_Weathers.EFFECTS = {};
var MOCK_EFFECT = {
	invalid:true,
	on:function(){},
	off:function(){},
	setValue:function(){return true}
};

var particleMoveValid = !!Game_Particle.prototype.particleMove;
EFFECTS.particle = window.Game_Particle ? {
	invalid:false,
	typeName:'パーティクル',
	onAfterSceneStart:false,
	onAfterTransfer:true,

	on:function(id,elemIdx,elem,elemData){
		var particleId = TRP_Weathers.elemId(id,elemIdx);
		var {configName,target,z,hue,color,loop,exceed} = elemData.typeParams;

		var particleData = Game_Particle.configDataWithName(configName);
		if(!particleData)return false;

		target = this.particleTarget(target);
		
		var alreadyExists = $gameScreen._particle._data[particleId];

		$gameScreen._particle.particleSet(0,particleId,target,configName,z);
		if((color&&color!=='#ffffff') || hue){
			$gameScreen._particle.rotateHue(particleId,hue,color);
		}
		if(loop && target==='weather'){
			$gameScreen._particle.particleLoop(particleId,loop,loop);
		}

		var needsFadeIn = particleFadeOut && particleMoveValid && alreadyExists;
		if(!alreadyExists){
			if(exceed && TRP_Weathers._onTransfer){
				$gameScreen._particle.particleExceed(particleId,exceed);
			}
		}

		//ParticleMZ_ExMove -> fadeIn if exists
		if(needsFadeIn){
			$gameScreen._particle.particleMove([particleId,particleFadeOut||60,'opacity',255,'noFilter']);
		}
	},
	particleTarget:target=>target,

	off:function(id,elemIdx,elem,elemData){
		var particleId = TRP_Weathers.elemId(id,elemIdx);
		$gameScreen._particle.particleClear(particleId);

		//ParticleMZ_ExMove
		if(particleFadeOut){
			$gameScreen._particle.particleMove?.([particleId,particleFadeOut,'opacity',0]);
		}
	},
	setValue:function(id,elemIdx,elem,elemData,value,params,duration){
		var particleId = TRP_Weathers.elemId(id,elemIdx);
		var particle = $gameScreen._particle._data[particleId];
		if(!particle)return true;

		if(!elem.cache){
			elem.cache = {
				data:Game_Particle.configData(particle),
				params:{},
			};
		}
		return this._setValue(elem.cache,particleId,params)
	},

	_setValue:function(cache,particleId,params,duration){
		var particleSettingData = cache.data;

		for(const key of params.keys){
			var paramRate = params[key];
			var paramData = cache.params[key]||null;
			if(!paramData){
				switch(key){
				case 'alpha':
				case 'scale':
				case 'speed':
					paramData = particleSettingData[key].list;
					break;
				case 'acceleration':
				case 'lifetime':
					paramData = particleSettingData[key];
					break;
				}
				cache.params[key] = paramData;
			}

			var args = [particleId,duration,key];

			if(key==='acceleration'){
				args.push(paramData.x*paramRate);
				args.push(paramData.y*paramRate);
			}else if(key==='lifetime'){
				args.push(paramData.min*paramRate);
				args.push(paramData.max*paramRate);
			}else if(paramData){
				//nodeParam
				var length = paramData.length;
				for(var i=0; i<length; i=(i+1)|0){
					args[3+i] = '%1@%2'.format(paramData[i].value*paramRate,paramData[i].time);
				}
			}else{
				//normalParam
				args.push(particleSettingData[key]*paramRate);
			}
			if(duration===0){
				args.splice(1,1);
				$gameScreen._particle.particleUpdate(args);
			}else{
				$gameScreen._particle.particleAnimate(args);
			}
		}
		return true;
	},
} : MOCK_EFFECT;


//=============================================================================
// EFFECT -> particleGroup (TRP_Particle)
//=============================================================================
TRP_Weathers.EFFECTS.particleGroup = window.Game_Particle ? {
	invalid:false,
	typeName:'パーティクルグループ',
	onAfterSceneStart:false,
	onAfterTransfer:true,

	innerIdForUpdate:function(id,groupId,replacedName){
		var subName = null;
		if(id.contains('::')){
			var elems = id.split('::');
			id = elems[0];
			subName = elems[1];
			if(/^_sub:[0-9]+$/.test(subName)){
				subName = subName.replace('_sub:','');
			}
		}
		if(/^_auto:[0-9]+$/.test(id)){
			id += ':'+replacedName+'/h';
		}
		id = id+'/GROUP:'+groupId;
		if(subName){
			id += '/SUB:'+subName;
		}
		return id;
	},
	on:function(id,elemIdx,elem,elemData){
		var groupId = TRP_Weathers.elemId(id,elemIdx);
		var {configName,target,hue,color,loop,exceed} = elemData.typeParams;

		var groupData = Game_Particle.groupDataWithName(configName);
		if(!groupData)return true;

		target = this.particleTarget(target);

		//ParticleMZ_ExMove -> fadeIn if exists
		if(particleFadeOut){
			$gameScreen._particle.particleMove?.(['group:'+groupId,particleFadeOut,'opacity',255]);
		}

		//groupSet
		var group = $gameScreen._particle.particleGroupSet(0,groupId,target,null,configName);
		group?.update();

		if((color&&color!=='#ffffff') || hue){
			EFFECTS.particleGroup.rotateColor(id,groupId,elemData,hue,color);
		}
		if(loop && target==='weather'){
			$gameScreen._particle.particleLoop('group:'+groupId,loop,loop);
		}
		if(exceed && TRP_Weathers._onTransfer){
			$gameScreen._particle.particleExceed('group:'+groupId,exceed);
		}
	},
	particleTarget:function(target){
		return target;
	},
	rotateColor:function(id,groupId,elemData,hue=elemData.typeParams.hue,color=elemData.typeParams.color){
		var configName = elemData.typeParams.configName;
		var any = elemData.values.find(v=>v.params)?.params?.data;
		if(!any)return;

		var replacedName = configName.replace('/h','');
		var innerIds = Object.keys(any);
		for(var innerId of innerIds){
			innerId = EFFECTS.particleGroup.innerIdForUpdate(innerId,groupId,replacedName);
			$gameScreen._particle.rotateHue(innerId,hue,color);
		}
	},


	off:(id,elemIdx,elem,elemData)=>{
		var particleId = TRP_Weathers.elemId(id,elemIdx);
		$gameScreen._particle.particleGroupClear(particleId);

		$gameScreen._particle.particleClear('tag:group:'+particleId);

		//ParticleMZ_ExMove
		if(particleFadeOut){
			$gameScreen._particle.particleMove?.(['tag:group:'+particleId,particleFadeOut,'opacity',0]);
		}
	},
	setValue:(id,elemIdx,elem,elemData,value,params,duration)=>{
		var groupId = TRP_Weathers.elemId(id,elemIdx);
		var configName = elemData.typeParams.configName;

		var groupData = Game_Particle.groupDataWithName(configName);
		if(!groupData)return true;

		var replacedName = configName.replace('/h','');
		var data = params.data;
		var innerIds = params.innerIds = params.innerIds||Object.keys(data);
		var keys = null;

		for(var innerId of innerIds){
			var idForUpdate = EFFECTS.particleGroup.innerIdForUpdate(innerId,groupId,replacedName);

			var particle = $gameScreen._particle.dataWithId(idForUpdate,true);
			if(!particle)continue;

			elem.cache = elem.cache||{};
			var cache = elem.cache[innerId]
			if(!cache){
				var configData;
				if(innerId.includes('::_sub:')){
					var subIdx = Number(innerId.split('::_sub:')[1]);
					var subName = particle.subs?.[subIdx]?.[0];
					configData = subName ? Game_Particle.configDataWithName(subName) : null;
				}else{
					configData = Game_Particle.configData(particle);
				}
				cache = elem.cache[innerId] = elem.cache[innerId]||{
					data:configData||null,
					params:{},
				};
			}
			if(!cache.data)continue;
			
			var innerParams = data[innerId];
			keys = innerParams.keys = innerParams.keys||keys||Object.keys(innerParams);
			EFFECTS.particle._setValue(cache,idForUpdate,innerParams,duration);
		}

		return true;
	}
} : MOCK_EFFECT;


//=============================================================================
// EFFECT -> weather (TRP_Weather)
//=============================================================================
TRP_Weathers.EFFECTS.weather = {
	invalid:false,
	typeName:'天候',
	onAfterSceneStart:false,
	onAfterTransfer:true,

	on:function(id,elemIdx,elem,elemData){
	},
	off:function(id,elemIdx,elem,elemData){
		var weathers = this.weathers();
		if(weathers.isCircularCall(id,elemData.typeParams.configName))return;
		weathers.clear(elemData.typeParams.configName);
	},
	setValue:function(id,elemIdx,elem,elemData,value,params,duration){
		var {configName} = elemData.typeParams;
		if(!$dataTrpWeathers[configName]){
			return true;
		}
		var weathers = this.weathers();
		if(weathers.isCircularCall(id,elemData.typeParams.configName))return;

		var init = !weathers._data[configName];
		weathers.set(
			configName,params.strength,duration,null,id
		);

		if(init){
			//set retain flag
			var weather = weathers._data[id];
			if(weather && weather._retain){
				weathers.retain(configName,true);
			}
			var child = weathers._data[configName];
			if(child){
				var {wiggleStrength,wiggleInterval,wiggleIntWidth,wiggleWait,wiggleWaitWidth,wiggleBack,wiggleDir,wiggleOptions} = elemData.typeParams;
				child.startWiggler(wiggleStrength,wiggleInterval,wiggleIntWidth,wiggleWait,wiggleWaitWidth,wiggleBack,wiggleDir,wiggleOptions);
			}
		}
		return true;
	},
	weathers:function(){return $trpWeathers},
};


