TRP_Weathers.EFFECTS.filter = window.TRP_FilterManager ? {
	invalid:false,
	typeName:'フィルタ',
	onAfterSceneStart:false,
	onAfterTransfer:true,
	
	on:function(id,elemIdx,elem,elemData){

	},
	off:function(id,elemIdx,elem,elemData){
		var idx = this.mapFilterId(elemData,id,elemIdx);
		TRP_FilterManager.updateMapFilters('<filter:>',0,undefined,idx);
	},
	setValue:function(id,elemIdx,elem,elemData,value,params,duration){
		if(!params.args)return true;
		var synthType = elemData.typeParams.synthesize;
		var target = elemData.typeParams.target;
		var args = params.args.map(a=>a.join(' ')+' '+synthType).join(',')

		var argsStr = '<filter:%1>'.format(args);
		var idx = this.mapFilterId(elemData,id,elemIdx);
		TRP_FilterManager.updateMapFilters(argsStr,duration,undefined,idx,target);
		return true;
	},
	mapFilterId:function(elemData,id,elemIdx){
		var result = (elemData.typeParams?.mapFilterId)||null;
		if(result==='auto'){
			result = TRP_Weathers.elemId(id,elemIdx);
		}
		return result;
	},
} : MOCK_EFFECT


