TRP_Weathers.EFFECTS.fog = TRP_CORE.FogSprite ? {
	invalid:false,
	typeName:'フォグ',
	onAfterSceneStart:false,
	onAfterTransfer:true,

	on:function(id,elemIdx,elem,elemData){
	},
	off:function(id,elemIdx,elem,elemData){
		// var anyArgs = elemData.values.find(v=>!!(v?.params?.args))?.params?.args?.concat();
		// while(anyArgs && anyArgs.length){
		// 	var endIdx = anyArgs.indexOf('|');
		// 	if(endIdx<0)endIdx = anyArgs.length;
		// 	var idx = anyArgs.splice(0,endIdx+1)[0];
		// 	$gameMap.trpFogTextureClear(idx,-1);
		// }

		var idxes = [];
		var fogDataOwner = this.fogDataOwner();
		for(const value of elemData.values){
			if(!value.params)continue;
			for(var args of value.params.args){
				var idx = this.fogIdx(TRP_CORE.last(args).replace('idx:',''),id,elemIdx);
				if(!TRP_CORE.uniquePush(idxes,idx))return;
				fogDataOwner.trpFogTextureClear(idx,-1);
			}
		}
	},
	setValue:function(id,elemIdx,elem,elemData,value,params,duration){
		var wholeArgs = params.args;
		var fogDataOwner = this.fogDataOwner();
		for(var args of wholeArgs){
			args = args.concat();
			var idx = this.fogIdx(args.pop().replace('idx:',''),id,elemIdx);
			args.unshift(idx);
			var argsStr = args.join(',');
			fogDataOwner.trpFogTextureChangeParameters([duration||1,argsStr]);
		}
		return true;
	},
	fogDataOwner:()=>$gameMap,
	fogIdx:function(idx,id,elemIdx){
		if(idx.indexOf('auto:')===0){
			var weatherId = TRP_Weathers.elemId(id,elemIdx);
			idx = idx.replace('auto',weatherId)
		}
		return idx;
	},
} : MOCK_EFFECT;


